"""AskUserTool - Built-in tool for LLM to request user input.

When the LLM needs a user decision, clarification, or approval, it calls this
tool with structured questions.  Execution blocks until the host application
returns the user's answers via an ``IUserInputHandler`` callback.

Design notes
------------
- The tool itself is a plain ITool; it knows nothing about the UI.
- All presentation logic lives in IUserInputHandler implementations
  (CLI, web, desktop, etc.).
- The handler is injected at construction time so the tool stays decoupled
  from any specific runtime.
"""

from __future__ import annotations

import asyncio
from abc import ABC, abstractmethod
from typing import Any, TypedDict

from dare_framework.tool.kernel import ITool
from dare_framework.tool.types import (
    CapabilityKind,
    RiskLevelName,
    RunContext,
    ToolResult,
    ToolType,
)


# ---------------------------------------------------------------------------
# Callback interface
# ---------------------------------------------------------------------------


class IUserInputHandler(ABC):
    """Callback that the host application implements to collect user input.

    The handler receives the structured question payload generated by the LLM
    and must return an ``answers`` dict that maps each question text to the
    user's selected option label (or free-text).
    """

    @abstractmethod
    async def handle(self, questions: list[dict[str, Any]]) -> dict[str, str]:
        """Present *questions* to the user and return their answers.

        Args:
            questions: A list of question objects, each containing:
                - ``question`` (str): The full question text.
                - ``header`` (str): Short label (≤ 12 chars).
                - ``options`` (list[dict]): 2-4 options, each with ``label``
                  and ``description``.
                - ``multiSelect`` (bool): Whether multiple selections are allowed.

        Returns:
            Mapping of ``question`` text → selected option ``label``(s).
            For multi-select, join labels with ``", "``.
        """
        ...


# ---------------------------------------------------------------------------
# Default CLI handler
# ---------------------------------------------------------------------------


class AutoUserInputHandler(IUserInputHandler):
    """Handler that responds automatically without blocking on user input.

    Used in fully autonomous execution modes (e.g. ``dare run --full-auto``)
    where the agent should never block waiting for human interaction.
    When options are available, the first option is selected; otherwise a
    configurable default response is returned.
    """

    DEFAULT_RESPONSE = "Proceed with your best judgment."

    def __init__(self, default_response: str | None = None) -> None:
        self._default_response = default_response or self.DEFAULT_RESPONSE

    async def handle(self, questions: list[dict[str, Any]]) -> dict[str, str]:
        answers: dict[str, str] = {}
        for q in questions:
            question_text = q.get("question", "")
            options = q.get("options", [])
            if options:
                answers[question_text] = options[0].get("label", self._default_response)
            else:
                answers[question_text] = self._default_response
        return answers


class CLIUserInputHandler(IUserInputHandler):
    """Simple stdin/stdout handler for command-line applications."""

    async def handle(self, questions: list[dict[str, Any]]) -> dict[str, str]:
        answers: dict[str, str] = {}

        for q in questions:
            header = q.get("header", "")
            question_text = q.get("question", "")
            options = q.get("options", [])
            multi = q.get("multiSelect", False)

            print(f"\n{'─' * 60}")
            if header:
                print(f"[{header}] {question_text}")
            else:
                print(question_text)

            for i, opt in enumerate(options, 1):
                label = opt.get("label", "")
                desc = opt.get("description", "")
                print(f"  {i}. {label}" + (f" - {desc}" if desc else ""))

            if multi:
                print("  (Enter numbers separated by commas, or type your answer)")
            else:
                print("  (Enter a number, or type your answer)")

            # Read input - run in executor to avoid blocking the event loop
            loop = asyncio.get_running_loop()
            raw = await loop.run_in_executor(None, lambda: input("Your choice: ").strip())

            answers[question_text] = self._parse_response(raw, options)

        return answers

    @staticmethod
    def _parse_response(raw: str, options: list[dict[str, Any]]) -> str:
        """Interpret *raw* as numbered selection(s) or free-text."""
        try:
            indices = [int(s.strip()) - 1 for s in raw.split(",")]
            labels = [
                options[i]["label"]
                for i in indices
                if 0 <= i < len(options)
            ]
            if labels:
                return ", ".join(labels)
        except (ValueError, IndexError):
            pass
        return raw


# ---------------------------------------------------------------------------
# Output TypedDict for schema inference
# ---------------------------------------------------------------------------


class AskUserOutput(TypedDict):
    """Output schema for ask_user tool."""
    answers: dict[str, str]


# ---------------------------------------------------------------------------
# The tool
# ---------------------------------------------------------------------------


class AskUserTool(ITool):
    """Built-in tool that allows the LLM to ask the user questions.

    The LLM calls this tool with structured questions (question text, options,
    multi-select flag).  The tool delegates to an ``IUserInputHandler`` which
    presents the questions to the user and returns their answers.

    Parameters
    ----------
    handler:
        An ``IUserInputHandler`` implementation.  Defaults to
        ``CLIUserInputHandler`` (stdin/stdout).
    """

    def __init__(self, handler: IUserInputHandler | None = None) -> None:
        self._handler: IUserInputHandler = handler or CLIUserInputHandler()

    # -- ITool metadata (trusted registry source) --

    @property
    def name(self) -> str:
        return "ask_user"

    @property
    def description(self) -> str:
        return (
            "Ask the user a question when you need clarification, a decision, "
            "or approval before proceeding. Present 1-4 structured questions "
            "with 2-4 options each. The user can select an option or provide "
            "free-text input."
        )

    @property
    def input_schema(self) -> dict[str, Any]:
        # Override auto-inference: the input is a complex nested structure
        # that cannot be cleanly represented as flat keyword params.
        return {
            "type": "object",
            "properties": {
                "questions": {
                    "type": "array",
                    "description": "1-4 questions to ask the user.",
                    "minItems": 1,
                    "maxItems": 4,
                    "items": {
                        "type": "object",
                        "properties": {
                            "question": {
                                "type": "string",
                                "description": "The full question text to display.",
                            },
                            "header": {
                                "type": "string",
                                "description": "Short label for the question (max 12 chars).",
                                "maxLength": 12,
                            },
                            "options": {
                                "type": "array",
                                "description": "2-4 choices for the user.",
                                "minItems": 2,
                                "maxItems": 4,
                                "items": {
                                    "type": "object",
                                    "properties": {
                                        "label": {
                                            "type": "string",
                                            "description": "Short display text for this option.",
                                        },
                                        "description": {
                                            "type": "string",
                                            "description": "Explanation of what this option means.",
                                        },
                                    },
                                    "required": ["label", "description"],
                                },
                            },
                            "multiSelect": {
                                "type": "boolean",
                                "description": "Whether the user can select multiple options.",
                                "default": False,
                            },
                        },
                        "required": ["question", "header", "options"],
                    },
                },
            },
            "required": ["questions"],
            "additionalProperties": False,
        }

    @property
    def output_schema(self) -> dict[str, Any]:
        return {
            "type": "object",
            "properties": {
                "answers": {
                    "type": "object",
                    "description": (
                        "Mapping of question text to the user's answer. "
                        "Each value is the selected option label or free-text."
                    ),
                    "additionalProperties": {"type": "string"},
                },
            },
            "required": ["answers"],
        }

    @property
    def tool_type(self) -> ToolType:
        return ToolType.ATOMIC

    @property
    def risk_level(self) -> RiskLevelName:
        return "read_only"

    @property
    def requires_approval(self) -> bool:
        return False

    @property
    def timeout_seconds(self) -> int:
        # User input can take a while; use a generous timeout.
        return 600

    @property
    def is_work_unit(self) -> bool:
        return False

    @property
    def capability_kind(self) -> CapabilityKind:
        return CapabilityKind.UI

    # -- Execution (new V5 signature: *, run_context, **params) --

    # noinspection PyMethodOverriding
    async def execute(
        self,
        *,
        run_context: RunContext[Any],
        questions: list[dict[str, Any]] | None = None,
    ) -> ToolResult[AskUserOutput]:
        """Execute the ask_user tool.

        Args:
            run_context: Runtime invocation context.
            questions: 1-4 structured questions for the user.

        Returns:
            Mapping of question text to user answers.
        """
        _ = run_context

        if not questions:
            return ToolResult(
                success=False,
                error="No questions provided. 'questions' array is required.",
            )

        try:
            answers = await self._handler.handle(questions)
        except Exception as exc:
            return ToolResult(
                success=False,
                error=f"Failed to collect user input: {exc}",
            )

        return ToolResult(
            success=True,
            output={"answers": answers},
        )


__all__ = [
    "AskUserTool",
    "AutoUserInputHandler",
    "CLIUserInputHandler",
    "IUserInputHandler",
]
